'use strict';

const _ = require('lodash');
const cookieModule = require('cookie');
const cookieUtils = require('../utils/cookie-utils');

function serializeCookies(req, cookies, sessionCookieName) {
  let cookieNames = Object.keys(cookies);
  let filteredCookies = cookieNames.filter(function (name) {
    return !shouldStripClientCookie(name, sessionCookieName);
  });
  if (filteredCookies.length === 0) {
    return null;
  }
  return filteredCookies.map(function (name) {
    return cookieUtils.serialize(req, name, cookies[name], { encode: same });
  }).join('; ');
}

function same(value) {
  return value;
}

function shouldStripClientCookie(name, sessionCookieName) {
  return (name === sessionCookieName) ||
    (name === '__VCAP_ID__') ||
    (_.startsWith(name.toLowerCase(), 'sapextlb'));
}

function stripCookieString(req, cookieHeader, sessionCookieName) {
  if (!cookieHeader) {
    return null;
  }
  let cookiesMap = cookieModule.parse(cookieHeader, { decode: same });
  return serializeCookies(req, cookiesMap, sessionCookieName);
}

module.exports = function stripClientCookies(req, sessionCookieName) {
  if (!req.headers.cookie) {
    return;
  }
  req.headers.cookie = stripCookieString(req, req.headers.cookie, sessionCookieName);
  if (req.headers.cookie === null) {
    delete req.headers.cookie;
  }
};

module.exports.stripCookieString = stripCookieString;
